      current = word
    elseif #current + #word + 1 <= width then
      current = current .. " " .. word
    else
      table.insert(lines, current)
      current = word
    end
  end

  if current ~= "" then table.insert(lines, current) end
  if #lines == 0 then table.insert(lines, "") end
  return lines
end

local function callout_width(buf)
