  local numbered = {}
  local n = start_index
  for _, section in ipairs(sections or {}) do
    local copy = vim.deepcopy(section)
    copy.note = string.format("[%02d] ", n) .. (copy.note or "")
    table.insert(numbered, copy)
    n = n + 1
  end
  return numbered, n
